sql:
SELECT recommended_size
FROM user_measurements 
WHERE bust_cm = (SELECT bust_cm FROM user_measurements WHERE user_id = 2001) AND user_id != 2001;

SELECT AVG(height_cm) 
FROM user_measurements 
WHERE fit_preference = 'Regular';

SELECT user_id
FROM user_measurements
WHERE bust_cm = (SELECT MAX(bust_cm) FROM user_measurements);

SELECT gender, MAX(waist_cm) AS max_waist_cm
FROM user_measurements
GROUP BY gender;

external_knowledge:
- "hidden treasures" refers to the unique identifiers, user IDs, and clothing sizes;
- "sizes that whisper the secrets of a perfect fit" refers to the recommended sizes;
- "measurements that dance with the rhythm" means the measurements fall within a specified range of tolerance;
- "5 cm embrace" represents the 5 cm range within which the measurements must fit.

sql:
SELECT s.international_size, s.region
FROM size_conversion s
JOIN user_measurements u ON s.international_size = u.recommended_size;

SELECT *
FROM size_conversion
WHERE international_size IN (
  SELECT recommended_size
  FROM user_measurements
  WHERE waist_cm > (
    SELECT AVG(waist_cm)
    FROM user_measurements
  )
);

SELECT AVG(height_cm) AS average_height_cm
FROM user_measurements
WHERE gender = 'women' AND fit_preference = 'regular';

SELECT user_id
FROM user_measurements
WHERE recommended_size = '44' AND height_cm < 182.88;

SELECT recommended_size
FROM user_measurements
WHERE user_id = 2001;
